#include<bits/stdc++.h>
using namespace std;
#define int long long
int n1,n2,n3,m,s,t,n,level[400114],edge[500005],nex[500005],w[500005],head[400114],cnt=2,ans=0;
void add_edge(int u,int v,int ww){
	edge[cnt]=v;
	w[cnt]=ww;
	nex[cnt]=head[u];
	head[u]=cnt++;

	edge[cnt]=u;
	w[cnt]=0;
	nex[cnt]=head[v];
	head[v]=cnt++;
}
queue<int> q;
bool bfs(){//在当前残量网络中跑分层图 
	for(int i=1;i<=n;i++){
		level[i]=-1;
	}
	while(!q.empty())q.pop(); 

	level[s]=0;
	q.push(s);
	while(q.size()>0){
		int u=q.front();
//		cout<<"u: "<<u<<" ";
		for(int i=head[u];i!=0;i=nex[i]){
			int v=edge[i];
			if(level[v]==-1&&w[i]>0){
				level[v]=level[u]+1;
				q.push(v);
			}
		}
//		cout<<"QwQ?\n"; 
		q.pop();
	}
	if(level[t]==-1){
		return false;
	}
	return true;
}
int dfs(int u,int flow){//找增广路 
	if(u==t){
		return flow;
	}
	int out=0;
	for(int i=head[u];i!=0;i=nex[i]){
		int v=edge[i];
		if(level[u]+1==level[v]&&w[i]>0){
			int tmp=dfs(v,min(flow,w[i]));
			w[i]-=tmp;
			w[i^1]+=tmp;
			out+=tmp;
			flow-=tmp;
			if(!flow)break;
		}
	}
	if(!out)level[u]=-1;return out;
}
signed main(){

	cin>>n1>>n2>>n3;
	n=n1*2+n2+n3+2;
	s=n1*2+n2+n3+1; 
	t=n1*2+n2+n3+2;
	cin>>m;
	for(int i=1;i<=m;i++){
		int u,v,ww=1;
		cin>>u>>v;
		//u是书,v是练习册 
		add_edge(v,u+n2,ww);
		add_edge(s,v,ww);
	}
	for(int u=1;u<=n1;++u)
		add_edge(u+n2,u+n1+n2,1);
	cin>>m;
	for(int i=1;i<=m;i++){
		int u,v,ww=1;
		cin>>u>>v;
		//u是书,v是答案  
		add_edge(u+n1+n2,v+n1+n1+n2,ww);
		add_edge(v+n1+n1+n2,t,ww);
	}

	while(bfs()){
		ans+=dfs(s,1e18);
	}
	cout<<ans;
}
